import { useEffect, useRef, useState } from "react";
import { motion } from "framer-motion";

const COVER = "data:image/jpeg;base64,";

const PLATES = [
  {
    src: "data:image/jpeg;base64,",
    index: "Plate 01",
    loc: "Cliffs of Moher",
    tag: "Ireland",
  },
  {
    src: "data:image/jpeg;base64,",
    index: "Plate 02",
    loc: "Giant's Causeway",
    tag: "Northern Ireland",
  },
  {
    src: "data:image/jpeg;base64,",
    index: "Plate 03",
    loc: "The Three Sisters",
    tag: "Blue Mountains, AU",
  },
  {
    src: "data:image/jpeg;base64,",
    index: "Plate 04",
    loc: "Wilsons Promontory",
    tag: "Victoria, AU",
  },
];

function Plate({ plate }) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) setVisible(true);
        });
      },
      { threshold: 0.18, rootMargin: "0px 0px -8% 0px" }
    );
    io.observe(el);
    return () => io.disconnect();
  }, []);

  return (
    <figure
      ref={ref}
      className={
        "max-w-5xl mx-auto mb-24 px-6 transition-all duration-1000 ease-out " +
        (visible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-24")
      }
    >
      <div className="relative rounded-md overflow-hidden shadow-2xl">
        <img src={plate.src} alt={plate.loc} className="w-full h-auto block" />
      </div>
      <div className="flex justify-between items-baseline mt-4 font-sans">
        <span className="text-[11px] tracking-widest text-orange-700">
          {plate.index}
        </span>
        <span className="font-serif text-lg text-stone-900">{plate.loc}</span>
        <span className="text-[11px] tracking-wide uppercase text-stone-400">
          {plate.tag}
        </span>
      </div>
    </figure>
  );
}

export default function WonderfulWorld() {
  return (
    <div className="bg-stone-50 font-serif text-stone-900">
      {/* Fixed cover hero */}
      <section className="fixed inset-0 w-full h-screen z-0">
        <img
          src={COVER}
          alt="Wonderful World — Australia's Majestic Landscapes"
          className="w-full h-full object-cover object-center block"
        />
        <div className="absolute inset-0 bg-gradient-to-b from-black/5 via-black/10 to-black/60" />
        <div className="absolute left-6 md:left-16 bottom-10 md:bottom-16 max-w-lg text-stone-50 z-10">
          <div className="uppercase tracking-[0.35em] text-[11px] font-sans opacity-85 mb-3">
            Magnum · Alok Sardana
          </div>
          <motion.h1 
            initial={{ opacity: 0, y: 30 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8 }}
            className="text-3xl md:text-5xl font-normal leading-tight"
          >
            Wonderful World
            <br />
            Coastlines, cliffs &amp; ancient stone
          </motion.h1>
        </div>
        <div className="absolute right-6 md:right-16 bottom-12 md:bottom-20 flex items-center gap-3 text-stone-50 font-sans text-[11px] tracking-[0.28em] uppercase opacity-85 z-10">
          <span className="w-px h-8 bg-stone-50 animate-pulse origin-top" />
          Scroll
        </div>
      </section>

      {/* Spacer to keep hero visible before the panel rises */}
      <div className="h-screen relative z-0" />

      {/* Scrolling panel that rises over the fixed hero */}
      <main className="relative z-10 bg-stone-50 rounded-t-3xl shadow-[0_-30px_60px_rgba(0,0,0,0.25)] pt-16 pb-10">
        <div className="text-center px-6 pb-12">
          <div className="uppercase tracking-[0.35em] text-[11px] font-sans text-orange-700 mb-3">
            The Plates
          </div>
          <motion.h2 
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8 }}
            className="text-2xl md:text-3xl font-normal"
          >
            Four views, one horizon
          </motion.h2>
          <motion.p 
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8, delay: 0.2 }}
            className="mt-3 font-sans text-sm text-stone-500 max-w-md mx-auto leading-relaxed"
          >
            Scroll to bring each photograph up from below — Ireland's cliffs,
            the Giant's Causeway, the Blue Mountains, and Wilsons Promontory.
          </motion.p>
        </div>

        {PLATES.map((plate) => (
          <Plate key={plate.index} plate={plate} />
        ))}

        <footer className="text-center pt-10 pb-4 font-sans text-[11px] tracking-[0.3em] uppercase text-stone-400">
          End of preview · Wonderful World
        </footer>
      </main>
    </div>
  );
}